"use client"

import { useEffect, useRef, useState } from "react"

type AnimatedNumberProps = {
  end: number
  duration?: number
  delay?: number
  className?: string
  prefix?: string
  suffix?: string
}

function AnimatedNumber({
  end,
  duration = 2000,
  delay = 0,
  className,
  prefix = "",
  suffix = ""
}: AnimatedNumberProps) {
  const [prefersReducedMotion, setPrefersReducedMotion] = useState(false)
  const [count, setCount] = useState(0)
  const [isVisible, setIsVisible] = useState(false)
  const ref = useRef<HTMLSpanElement>(null)

  useEffect(() => {
    const mediaQuery = window.matchMedia("(prefers-reduced-motion: reduce)")

    const updatePreference = () => {
      setPrefersReducedMotion(mediaQuery.matches)
    }

    updatePreference()

    if (typeof mediaQuery.addEventListener === "function") {
      mediaQuery.addEventListener("change", updatePreference)
      return () => mediaQuery.removeEventListener("change", updatePreference)
    }

    mediaQuery.addListener(updatePreference)

    return () => mediaQuery.removeListener(updatePreference)
  }, [])

  useEffect(() => {
    if (prefersReducedMotion) {
      setCount(end)
      return
    }

    setCount(0)

    const observer = new IntersectionObserver(
      ([entry]) => {
        if (entry.isIntersecting) {
          setIsVisible(true)
          observer.unobserve(entry.target)
        }
      },
      { threshold: 0.1 }
    )

    const current = ref.current

    if (current) {
      observer.observe(current)
    }

    return () => {
      if (current) {
        observer.unobserve(current)
      }

      observer.disconnect()
    }
  }, [prefersReducedMotion, end])

  useEffect(() => {
    if (prefersReducedMotion || !isVisible) {
      return
    }

    const timeoutId = window.setTimeout(() => {
      const start = performance.now()

      const animate = (timestamp: number) => {
        const progress = Math.min((timestamp - start) / duration, 1)
        const easeOutQuart = 1 - Math.pow(1 - progress, 4)
        setCount(Math.floor(easeOutQuart * end))

        if (progress < 1) {
          requestAnimationFrame(animate)
        }
      }

      requestAnimationFrame(animate)
    }, delay)

    return () => window.clearTimeout(timeoutId)
  }, [delay, duration, end, isVisible, prefersReducedMotion])

  return (
    <span ref={ref} className={className} style={{ fontVariantNumeric: "tabular-nums" }}>
      {prefix}
      {count}
      {suffix}
    </span>
  )
}

export { AnimatedNumber }

"use client"

import { Fragment, useEffect, useMemo, useRef, useState } from "react"

import { cn } from "@/lib/utils"

type AnimatedTextProps = {
  text: string
  className?: string
  wordClassName?: string
  delayMs?: number
  staggerMs?: number
  threshold?: number
  immediate?: boolean
}

function AnimatedText({
  text,
  className,
  wordClassName,
  delayMs = 0,
  staggerMs = 70,
  threshold = 0.2,
  immediate = false
}: AnimatedTextProps) {
  const containerRef = useRef<HTMLSpanElement>(null)
  const [isVisible, setIsVisible] = useState(immediate)
  const [prefersReducedMotion, setPrefersReducedMotion] = useState(false)

  const words = useMemo(() => text.trim().split(/\s+/).filter(Boolean), [text])

  useEffect(() => {
    const mediaQuery = window.matchMedia("(prefers-reduced-motion: reduce)")

    const updatePreference = () => {
      setPrefersReducedMotion(mediaQuery.matches)
    }

    updatePreference()

    if (typeof mediaQuery.addEventListener === "function") {
      mediaQuery.addEventListener("change", updatePreference)
      return () => mediaQuery.removeEventListener("change", updatePreference)
    }

    mediaQuery.addListener(updatePreference)

    return () => mediaQuery.removeListener(updatePreference)
  }, [])

  useEffect(() => {
    if (immediate || prefersReducedMotion) {
      setIsVisible(true)
      return
    }

    const element = containerRef.current

    if (!element) {
      return
    }

    const observer = new IntersectionObserver(
      ([entry]) => {
        if (entry.isIntersecting) {
          setIsVisible(true)
          observer.unobserve(entry.target)
        }
      },
      {
        threshold,
        rootMargin: "0px 0px -10% 0px"
      }
    )

    observer.observe(element)

    return () => observer.disconnect()
  }, [immediate, prefersReducedMotion, threshold])

  return (
    <span ref={containerRef} className={cn(className)}>
      {words.map((word, index) => {
        const visible = isVisible || prefersReducedMotion

        return (
          <Fragment key={`${word}-${index}`}>
            <span
              data-visible={visible ? "true" : "false"}
              className={cn("bp-text-word", wordClassName)}
              style={{
                display: "inline-block",
                opacity: visible ? 1 : 0,
                transform: visible ? "translate3d(0, 0, 0)" : "translate3d(0, 0.45em, 0)",
                filter: visible ? "none" : "blur(6px)",
                transitionProperty: "opacity, transform, filter",
                transitionDuration: prefersReducedMotion ? "0ms" : "700ms",
                transitionTimingFunction: "cubic-bezier(0.16, 1, 0.3, 1)",
                transitionDelay: prefersReducedMotion ? "0ms" : `${delayMs + index * staggerMs}ms`,
                willChange: visible ? "auto" : "opacity, transform, filter"
              }}
            >
              {word}
            </span>
            {index < words.length - 1 ? " " : null}
          </Fragment>
        )
      })}
    </span>
  )
}

export { AnimatedText }

"use client"

import * as React from "react"

import { cn } from "@/lib/utils"

type Card3DProps = {
  children: React.ReactNode
  className?: string
  intensity?: number
}

function Card3D({ children, className, intensity = 1 }: Card3DProps) {
  const cardRef = React.useRef<HTMLDivElement>(null)
  const innerRef = React.useRef<HTMLDivElement>(null)
  const frameRef = React.useRef<number | null>(null)
  const targetRef = React.useRef({ rotateX: 0, rotateY: 0 })
  const currentRef = React.useRef({ rotateX: 0, rotateY: 0 })
  const canAnimateRef = React.useRef(true)

  React.useEffect(() => {
    const reducedMotion = window.matchMedia("(prefers-reduced-motion: reduce)")
    const coarsePointer = window.matchMedia("(pointer: coarse)")

    const updateCapability = () => {
      canAnimateRef.current = !(reducedMotion.matches || coarsePointer.matches)

      if (!canAnimateRef.current && innerRef.current) {
        innerRef.current.style.transform = "perspective(1000px) rotateX(0deg) rotateY(0deg) translateZ(0)"
      }
    }

    updateCapability()

    const listeners: Array<[MediaQueryList, () => void]> = [
      [reducedMotion, updateCapability],
      [coarsePointer, updateCapability]
    ]

    listeners.forEach(([query, listener]) => {
      if (typeof query.addEventListener === "function") {
        query.addEventListener("change", listener)
        return
      }

      query.addListener(listener)
    })

    return () => {
      listeners.forEach(([query, listener]) => {
        if (typeof query.removeEventListener === "function") {
          query.removeEventListener("change", listener)
          return
        }

        query.removeListener(listener)
      })

      if (frameRef.current !== null) {
        cancelAnimationFrame(frameRef.current)
      }
    }
  }, [])

  const animate = React.useCallback(() => {
    const inner = innerRef.current
    frameRef.current = null

    if (!inner) {
      return
    }

    const current = currentRef.current
    const target = targetRef.current

    current.rotateX += (target.rotateX - current.rotateX) * 0.2
    current.rotateY += (target.rotateY - current.rotateY) * 0.2

    inner.style.transform = `perspective(1000px) rotateX(${current.rotateX.toFixed(2)}deg) rotateY(${current.rotateY.toFixed(2)}deg) translateZ(0)`

    const shouldContinue =
      Math.abs(target.rotateX - current.rotateX) > 0.05 || Math.abs(target.rotateY - current.rotateY) > 0.05

    if (shouldContinue) {
      frameRef.current = requestAnimationFrame(animate)
    }
  }, [])

  const queueFrame = React.useCallback(() => {
    if (frameRef.current === null) {
      frameRef.current = requestAnimationFrame(animate)
    }
  }, [animate])

  const handlePointerMove = (event: React.PointerEvent<HTMLDivElement>) => {
    if (!canAnimateRef.current || !cardRef.current) {
      return
    }

    const rect = cardRef.current.getBoundingClientRect()
    const x = event.clientX - rect.left
    const y = event.clientY - rect.top

    const centerX = rect.width / 2
    const centerY = rect.height / 2

    targetRef.current = {
      rotateX: ((y - centerY) / centerY) * -10 * intensity,
      rotateY: ((x - centerX) / centerX) * 10 * intensity
    }

    queueFrame()
  }

  const handlePointerLeave = () => {
    targetRef.current = { rotateX: 0, rotateY: 0 }
    queueFrame()
  }

  return (
    <div
      ref={cardRef}
      className={cn("card-3d", className)}
      onPointerMove={handlePointerMove}
      onPointerLeave={handlePointerLeave}
      onPointerCancel={handlePointerLeave}
    >
      <div
        ref={innerRef}
        className="card-3d-inner h-full"
        style={{
          transform: "perspective(1000px) rotateX(0deg) rotateY(0deg) translateZ(0)",
          backfaceVisibility: "hidden",
          willChange: "transform"
        }}
      >
        {children}
      </div>
    </div>
  )
}

export { Card3D }

"use client"

import * as React from "react"
import { Slot } from "@radix-ui/react-slot"

import { cn } from "@/lib/utils"

type MagneticButtonProps = Omit<React.ComponentProps<"button">, "onPointerMove" | "onPointerLeave"> & {
  strength?: number
  asChild?: boolean
  onPointerMove?: React.PointerEventHandler<HTMLElement>
  onPointerLeave?: React.PointerEventHandler<HTMLElement>
}

function MagneticButton({
  className,
  strength = 0.3,
  asChild = false,
  onPointerMove,
  onPointerLeave,
  style,
  disabled,
  ...props
}: MagneticButtonProps) {
  const ref = React.useRef<HTMLElement>(null)
  const frameRef = React.useRef<number | null>(null)
  const targetRef = React.useRef({ x: 0, y: 0 })
  const currentRef = React.useRef({ x: 0, y: 0 })
  const canAnimateRef = React.useRef(true)

  React.useEffect(() => {
    const reducedMotion = window.matchMedia("(prefers-reduced-motion: reduce)")
    const coarsePointer = window.matchMedia("(pointer: coarse)")

    const updateCapability = () => {
      canAnimateRef.current = !(reducedMotion.matches || coarsePointer.matches)

      if (!canAnimateRef.current) {
        const element = ref.current

        if (element) {
          element.style.setProperty("--bp-magnetic-x", "0px")
          element.style.setProperty("--bp-magnetic-y", "0px")
        }
      }
    }

    updateCapability()

    const listeners: Array<[MediaQueryList, () => void]> = [
      [reducedMotion, updateCapability],
      [coarsePointer, updateCapability]
    ]

    listeners.forEach(([query, listener]) => {
      if (typeof query.addEventListener === "function") {
        query.addEventListener("change", listener)
        return
      }

      query.addListener(listener)
    })

    return () => {
      listeners.forEach(([query, listener]) => {
        if (typeof query.removeEventListener === "function") {
          query.removeEventListener("change", listener)
          return
        }

        query.removeListener(listener)
      })

      if (frameRef.current !== null) {
        cancelAnimationFrame(frameRef.current)
      }
    }
  }, [])

  React.useEffect(() => {
    if (!disabled || !ref.current) {
      return
    }

    targetRef.current = { x: 0, y: 0 }
    currentRef.current = { x: 0, y: 0 }
    ref.current.style.setProperty("--bp-magnetic-x", "0px")
    ref.current.style.setProperty("--bp-magnetic-y", "0px")
  }, [disabled])

  const animate = React.useCallback(() => {
    const element = ref.current
    frameRef.current = null

    if (!element) {
      return
    }

    const current = currentRef.current
    const target = targetRef.current

    current.x += (target.x - current.x) * 0.22
    current.y += (target.y - current.y) * 0.22

    element.style.setProperty("--bp-magnetic-x", `${current.x.toFixed(2)}px`)
    element.style.setProperty("--bp-magnetic-y", `${current.y.toFixed(2)}px`)

    const shouldContinue = Math.abs(target.x - current.x) > 0.05 || Math.abs(target.y - current.y) > 0.05

    if (shouldContinue) {
      frameRef.current = requestAnimationFrame(animate)
    }
  }, [])

  const queueFrame = React.useCallback(() => {
    if (frameRef.current === null) {
      frameRef.current = requestAnimationFrame(animate)
    }
  }, [animate])

  const handlePointerMove = (event: React.PointerEvent<HTMLElement>) => {
    onPointerMove?.(event)

    if (disabled || !canAnimateRef.current || !ref.current) {
      return
    }

    const rect = ref.current.getBoundingClientRect()
    const offsetX = event.clientX - rect.left - rect.width / 2
    const offsetY = event.clientY - rect.top - rect.height / 2

    targetRef.current = {
      x: offsetX * strength,
      y: offsetY * strength
    }

    queueFrame()
  }

  const handlePointerLeave = (event: React.PointerEvent<HTMLElement>) => {
    onPointerLeave?.(event)
    targetRef.current = { x: 0, y: 0 }
    queueFrame()
  }

  const Comp = asChild ? Slot : "button"

  return (
    <Comp
      ref={ref as React.RefObject<never>}
      className={cn("magnetic-button", className)}
      onPointerMove={handlePointerMove}
      onPointerLeave={handlePointerLeave}
      style={{
        ...style,
        ["--bp-magnetic-x" as string]: "0px",
        ["--bp-magnetic-y" as string]: "0px"
      }}
      disabled={disabled}
      {...props}
    />
  )
}

export { MagneticButton }
